const TheWellspring=(()=>{'use strict';const DB_NAME='FlockOS_Wellspring';const DB_VERSION=1;const STORE_NAME='sheets';const META_STORE='meta';const LS_KEY='flock_wellspring_mode';const SPRINGS={app:{prefix:'app:',label:'Matthew (App)',gospel:'Matthew'},flock:{prefix:'flock:',label:'John (Flock)',gospel:'John'},missions:{prefix:'missions:',label:'Mark (Missions)',gospel:'Mark'},extra:{prefix:'extra:',label:'Luke (Extra)',gospel:'Luke'},};const GOSPEL_TO_SPRING={matthew:'app',john:'flock',mark:'missions',luke:'extra'};let _db=null;let _active=false;function _openDB(){if(_db)return Promise.resolve(_db);return new Promise((resolve,reject)=>{const req=indexedDB.open(DB_NAME,DB_VERSION);req.onupgradeneeded=(e)=>{const db=e.target.result;if(!db.objectStoreNames.contains(STORE_NAME)){db.createObjectStore(STORE_NAME);}
if(!db.objectStoreNames.contains(META_STORE)){db.createObjectStore(META_STORE);}};req.onsuccess=()=>{_db=req.result;resolve(_db);};req.onerror=()=>reject(new Error('Wellspring: IndexedDB open failed'));});}
function _tx(storeName,mode){return _db.transaction(storeName,mode).objectStore(storeName);}
function _put(storeName,key,value){return new Promise((resolve,reject)=>{const req=_tx(storeName,'readwrite').put(value,key);req.onsuccess=()=>resolve();req.onerror=()=>reject(req.error);});}
function _get(storeName,key){return new Promise((resolve,reject)=>{const req=_tx(storeName,'readonly').get(key);req.onsuccess=()=>resolve(req.result);req.onerror=()=>reject(req.error);});}
function _del(storeName,key){return new Promise((resolve,reject)=>{const req=_tx(storeName,'readwrite').delete(key);req.onsuccess=()=>resolve();req.onerror=()=>reject(req.error);});}
function _allKeys(storeName){return new Promise((resolve,reject)=>{const req=_tx(storeName,'readonly').getAllKeys();req.onsuccess=()=>resolve(req.result||[]);req.onerror=()=>reject(req.error);});}
async function load(spring,file){if(!SPRINGS[spring])throw new Error('Wellspring: unknown spring "'+spring+'"');if(typeof XLSX==='undefined')throw new Error('Wellspring: SheetJS (XLSX) library not loaded. Add the CDN script tag.');await _openDB();const prefix=SPRINGS[spring].prefix;const existingKeys=await _allKeys(STORE_NAME);for(const key of existingKeys){if(key.startsWith(prefix))await _del(STORE_NAME,key);}
const arrayBuffer=await file.arrayBuffer();const workbook=XLSX.read(arrayBuffer,{type:'array',cellDates:true});const tabs=workbook.SheetNames;const rowCounts={};for(const tabName of tabs){const sheet=workbook.Sheets[tabName];const rows=XLSX.utils.sheet_to_json(sheet,{defval:''});await _put(STORE_NAME,prefix+tabName,rows);rowCounts[tabName]=rows.length;}
await _put(META_STORE,spring,{loadedAt:new Date().toISOString(),fileName:file.name,fileSize:file.size,tabCount:tabs.length,tabs:tabs,rowCounts:rowCounts,});return{tabs,rowCounts};}
async function getTab(spring,tabName){await _openDB();const key=SPRINGS[spring].prefix+tabName;const data=await _get(STORE_NAME,key);return data||[];}
async function findById(spring,tabName,id){const rows=await getTab(spring,tabName);for(let i=0;i<rows.length;i++){const row=rows[i];const rowId=row.id||row.Id||row.ID||Object.values(row)[0];if(String(rowId)===String(id)){return{rowIndex:i,row};}}
return null;}
async function appendRow(spring,tabName,rowData){const rows=await getTab(spring,tabName);rows.push(rowData);await _put(STORE_NAME,SPRINGS[spring].prefix+tabName,rows);return rowData;}
async function updateRow(spring,tabName,id,updates){const rows=await getTab(spring,tabName);for(let i=0;i<rows.length;i++){const row=rows[i];const rowId=row.id||row.Id||row.ID||Object.values(row)[0];if(String(rowId)===String(id)){Object.assign(rows[i],updates);await _put(STORE_NAME,SPRINGS[spring].prefix+tabName,rows);return rows[i];}}
return null;}
async function deleteRow(spring,tabName,id){const rows=await getTab(spring,tabName);const before=rows.length;const filtered=rows.filter(row=>{const rowId=row.id||row.Id||row.ID||Object.values(row)[0];return String(rowId)!==String(id);});if(filtered.length===before)return false;await _put(STORE_NAME,SPRINGS[spring].prefix+tabName,filtered);return true;}
async function resolve(action,params){params=params||{};if(action==='app.tab'){const tabName=params.tab;if(!tabName)return{ok:false,error:'Missing tab name'};const rows=await getTab('app',tabName);return rows;}
if(action==='health'){return{ok:true,mode:'local',source:'TheWellspring',timestamp:new Date().toISOString()};}
const spring=_actionToSpring(action);if(!spring)return undefined;const parts=action.split('.');const entity=parts.length>1?parts.slice(0,-1).join('.'):parts[0];const verb=parts[parts.length-1];const tabName=_entityToTab(entity);if(!tabName)return undefined;switch(verb){case'list':{let rows=await getTab(spring,tabName);rows=_applyFilters(rows,params);return{ok:true,data:rows,count:rows.length};}
case'get':{if(!params.id)return{ok:false,error:'Missing id'};const found=await findById(spring,tabName,params.id);if(!found)return{ok:false,error:'Not found'};return{ok:true,data:found.row};}
case'create':{if(!params.id)params.id=_uuid();params.createdAt=params.createdAt||new Date().toISOString();params.updatedAt=params.updatedAt||params.createdAt;const newRow=await appendRow(spring,tabName,params);return{ok:true,data:newRow};}
case'update':{if(!params.id)return{ok:false,error:'Missing id'};params.updatedAt=new Date().toISOString();const updated=await updateRow(spring,tabName,params.id,params);if(!updated)return{ok:false,error:'Not found'};return{ok:true,data:updated};}
case'delete':{if(!params.id)return{ok:false,error:'Missing id'};const deleted=await deleteRow(spring,tabName,params.id);return{ok:deleted,message:deleted?'Deleted':'Not found'};}
case'search':{let rows=await getTab(spring,tabName);if(params.q){const q=String(params.q).toLowerCase();rows=rows.filter(r=>JSON.stringify(Object.values(r)).toLowerCase().includes(q));}
return{ok:true,data:rows,count:rows.length};}
case'summary':case'dashboard':{const rows=await getTab(spring,tabName);return{ok:true,data:rows,count:rows.length,source:'local'};}
default:return undefined;}}
function _actionToSpring(action){const flockPrefixes=['auth','users','access','config','members','prayer','journal','contacts','notes','milestones','households','todo','attendance','events','groups','giving','volunteers','comms','checkin','ministries','ministryMembers','servicePlans','serviceItems','care','outreach','sermons','sermonSeries','sermonReviews','compassion','discipleship','learning','theology','memberCards','user','reports','church','bulk','audit','songs',];const missionsPrefixes=['missions'];const extraPrefixes=['statistics'];const root=action.split('.')[0];if(flockPrefixes.includes(root))return'flock';if(missionsPrefixes.includes(root))return'missions';if(extraPrefixes.includes(root))return'extra';if(root==='app')return'app';return null;}
function _entityToTab(entity){const MAP={'auth':'AuthUsers','users':'AuthUsers','access':'AccessControl','config':'AppConfig','members':'Members','prayer':'PrayerRequests','journal':'JournalEntries','contacts':'ContactLog','notes':'PastoralNotes','milestones':'Milestones','households':'Households','todo':'ToDo','attendance':'Attendance','events':'Events','groups':'SmallGroups','audit':'AuditLog','giving':'Giving','giving.pledges':'GivingPledges','volunteers':'VolunteerSchedule','comms':'CommsMessages','comms.messages':'CommsMessages','comms.threads':'CommsThreads','comms.notifications':'CommsNotifications','comms.notifPrefs':'CommsNotifPrefs','comms.channels':'CommsChannels','comms.templates':'CommsTemplates','comms.readReceipts':'CommsReadReceipts','comms.broadcast':'CommsBroadcasts','checkin':'CheckInSessions','ministries':'Ministries','ministryMembers':'MinistryMembers','servicePlans':'ServicePlans','serviceItems':'ServicePlanItems','care':'SpiritualCareCases','care.interactions':'SpiritualCareInteractions','care.followUps':'SpiritualCareCases','care.assignments':'CareAssignments','outreach':'OutreachContacts','outreach.contacts':'OutreachContacts','outreach.campaigns':'OutreachCampaigns','outreach.followUps':'OutreachContacts','sermons':'Sermons','sermonSeries':'SermonSeries','sermonReviews':'SermonReviews','songs':'Songs','compassion':'CompassionRequests','compassion.requests':'CompassionRequests','compassion.followUps':'CompassionRequests','compassion.resources':'CompassionResources','compassion.log':'CompassionLog','discipleship':'DiscipleshipPaths','discipleship.paths':'DiscipleshipPaths','discipleship.steps':'DiscipleshipSteps','discipleship.enrollments':'DiscipleshipEnrollments','discipleship.mentoring':'DiscipleshipMentoring','discipleship.meetings':'DiscipleshipMeetings','discipleship.assessments':'DiscipleshipAssessments','discipleship.resources':'DiscipleshipResources','discipleship.milestones':'DiscipleshipMilestones','discipleship.goals':'DiscipleshipGoals','discipleship.certificates':'DiscipleshipCertificates','learning':'LearningTopics','learning.topics':'LearningTopics','learning.playlists':'LearningPlaylists','learning.playlistItems':'LearningPlaylistItems','learning.progress':'LearningProgress','learning.notes':'LearningNotes','learning.bookmarks':'LearningBookmarks','learning.recommendations':'LearningRecommendations','learning.quizzes':'LearningQuizzes','learning.quizResults':'LearningQuizResults','learning.certificates':'LearningCertificates','learning.sermons':'Sermons','theology':'TheologyCategories','theology.categories':'TheologyCategories','theology.sections':'TheologySections','theology.scriptures':'TheologyScriptures','theology.revisions':'TheologyRevisions','memberCards':'MemberCards','memberCards.links':'MemberCardLinks','memberCards.views':'MemberCardViews','reports':'Members','user.preferences':'UserProfiles','church':'AppConfig','bulk':'Members','missions':'MissionsRegistry','missions.registry':'MissionsRegistry','missions.regions':'MissionsRegions','missions.cities':'MissionsCities','missions.partners':'MissionsPartners','missions.prayerFocus':'MissionsPrayerFocus','missions.updates':'MissionsUpdates','missions.teams':'MissionsTeams','missions.metrics':'MissionsMetrics','statistics':'StatisticsConfig','statistics.config':'StatisticsConfig','statistics.snapshots':'StatisticsSnapshots','statistics.views':'StatisticsViews',};return MAP[entity]||null;}
function _applyFilters(rows,params){const skip=['action','token','authEmail','email','_','limit','offset'];const filters={};for(const k of Object.keys(params)){if(!skip.includes(k)&&params[k]!==''&&params[k]!=null){filters[k]=String(params[k]).toLowerCase();}}
if(Object.keys(filters).length===0)return rows;return rows.filter(row=>{for(const[key,val]of Object.entries(filters)){const rowVal=row[key];if(rowVal==null)return false;if(String(rowVal).toLowerCase()!==val)return false;}
return true;});}
function _uuid(){if(typeof crypto!=='undefined'&&crypto.randomUUID)return crypto.randomUUID();return'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g,c=>{const r=(Math.random()*16)|0;return(c==='x'?r:(r&0x3)|0x8).toString(16);});}
async function enable(){await _openDB();_active=true;localStorage.setItem(LS_KEY,'true');if(typeof TheVine!=='undefined'){TheVine.configure({LOCAL_RESOLVER:resolve});}
console.log('[Wellspring] Local data mode ENABLED — "Whoever drinks this water will never thirst." John 4:14');}
function disable(){_active=false;localStorage.removeItem(LS_KEY);if(typeof TheVine!=='undefined'){TheVine.configure({LOCAL_RESOLVER:null});}
console.log('[Wellspring] Local data mode DISABLED — returning to cloud.');}
function isActive(){return _active;}
async function exportSpring(spring){if(!SPRINGS[spring])throw new Error('Wellspring: unknown spring "'+spring+'"');if(typeof XLSX==='undefined')throw new Error('Wellspring: SheetJS not loaded.');await _openDB();const meta=await _get(META_STORE,spring);if(!meta||!meta.tabs)throw new Error('No local data loaded for '+SPRINGS[spring].label);const workbook=XLSX.utils.book_new();for(const tabName of meta.tabs){const rows=await getTab(spring,tabName);const sheet=XLSX.utils.json_to_sheet(rows);XLSX.utils.book_append_sheet(workbook,sheet,tabName);}
const fileName=SPRINGS[spring].gospel+'_FlockOS_'+new Date().toISOString().slice(0,10)+'.xlsx';XLSX.writeFile(workbook,fileName);return fileName;}
async function exportAll(){const exported=[];for(const spring of Object.keys(SPRINGS)){try{const meta=await _get(META_STORE,spring);if(meta&&meta.tabs){const name=await exportSpring(spring);exported.push(name);}}catch(_){}}
return exported;}
async function status(){await _openDB();const springs={};for(const[key,info]of Object.entries(SPRINGS)){const meta=await _get(META_STORE,key);springs[key]=meta?{loaded:true,gospel:info.gospel,label:info.label,fileName:meta.fileName,fileSize:meta.fileSize,tabCount:meta.tabCount,loadedAt:meta.loadedAt,}:{loaded:false,gospel:info.gospel,label:info.label,};}
return{active:_active,springs};}
async function clearSpring(spring){if(!SPRINGS[spring])throw new Error('Wellspring: unknown spring "'+spring+'"');await _openDB();const prefix=SPRINGS[spring].prefix;const keys=await _allKeys(STORE_NAME);for(const key of keys){if(key.startsWith(prefix))await _del(STORE_NAME,key);}
await _del(META_STORE,spring);}
async function clearAll(){for(const spring of Object.keys(SPRINGS)){await clearSpring(spring);}}
function _autoInit(){if(localStorage.getItem(LS_KEY)==='true'){setTimeout(()=>{enable().catch(e=>console.warn('[Wellspring] Auto-enable failed:',e));},0);}}
_autoInit();return Object.freeze({enable,disable,isActive,resolve,load,exportSpring,exportAll,getTab,findById,appendRow,updateRow,deleteRow,status,clearSpring,clearAll,SPRINGS,vault:Object.freeze({setup:_vaultSetup,unlock:_vaultUnlock,exists:_vaultExists,destroy:_vaultDestroy,}),});const VAULT_STORE='vault';const VAULT_KEY='credentials';const VAULT_ITERATIONS=100000;function _ensureVaultStore(){return new Promise(function(resolve,reject){var req=indexedDB.open(DB_NAME,DB_VERSION+1);req.onupgradeneeded=function(e){var db=e.target.result;if(!db.objectStoreNames.contains(VAULT_STORE)){db.createObjectStore(VAULT_STORE);}};req.onsuccess=function(){_db=req.result;resolve();};req.onerror=function(){reject(new Error('Vault store init failed'));};});}
async function _vaultSetup(pin,sessionData){if(!pin||pin.length<6)throw new Error('PIN must be at least 6 characters');await _ensureVaultStore();var salt=crypto.getRandomValues(new Uint8Array(16));var iv=crypto.getRandomValues(new Uint8Array(12));var key=await _deriveKey(pin,salt);var plain=new TextEncoder().encode(JSON.stringify(sessionData));var cipher=await crypto.subtle.encrypt({name:'AES-GCM',iv:iv},key,plain);var blob={salt:Array.from(salt),iv:Array.from(iv),cipher:Array.from(new Uint8Array(cipher)),createdAt:Date.now(),expiresAt:Date.now()+(30*24*60*60*1000),};await _ensureVaultStore();return new Promise(function(resolve,reject){var tx=_db.transaction(VAULT_STORE,'readwrite');tx.objectStore(VAULT_STORE).put(blob,VAULT_KEY);tx.oncomplete=function(){resolve();};tx.onerror=function(){reject(new Error('Vault write failed'));};});}
async function _vaultUnlock(pin){await _ensureVaultStore();var blob=await new Promise(function(resolve,reject){var tx=_db.transaction(VAULT_STORE,'readonly');var req=tx.objectStore(VAULT_STORE).get(VAULT_KEY);req.onsuccess=function(){resolve(req.result);};req.onerror=function(){reject(new Error('Vault read failed'));};});if(!blob)throw new Error('No vault found — set up offline access first');if(blob.expiresAt&&Date.now()>blob.expiresAt){await _vaultDestroy();throw new Error('Vault expired — please log in online to re-enable offline access');}
var salt=new Uint8Array(blob.salt);var iv=new Uint8Array(blob.iv);var cipher=new Uint8Array(blob.cipher);var key=await _deriveKey(pin,salt);try{var plain=await crypto.subtle.decrypt({name:'AES-GCM',iv:iv},key,cipher);var session=JSON.parse(new TextDecoder().decode(plain));session.offline=true;session.offlineUnlockedAt=Date.now();return session;}catch(_){throw new Error('Invalid PIN');}}
async function _vaultExists(){try{await _ensureVaultStore();var blob=await new Promise(function(resolve,reject){var tx=_db.transaction(VAULT_STORE,'readonly');var req=tx.objectStore(VAULT_STORE).get(VAULT_KEY);req.onsuccess=function(){resolve(req.result);};req.onerror=function(){resolve(null);};});return!!blob&&(!blob.expiresAt||Date.now()<blob.expiresAt);}catch(_){return false;}}
async function _vaultDestroy(){await _ensureVaultStore();return new Promise(function(resolve,reject){var tx=_db.transaction(VAULT_STORE,'readwrite');tx.objectStore(VAULT_STORE).delete(VAULT_KEY);tx.oncomplete=function(){resolve();};tx.onerror=function(){reject(new Error('Vault delete failed'));};});}
async function _deriveKey(pin,salt){var raw=await crypto.subtle.importKey('raw',new TextEncoder().encode(pin),'PBKDF2',false,['deriveKey']);return crypto.subtle.deriveKey({name:'PBKDF2',salt:salt,iterations:VAULT_ITERATIONS,hash:'SHA-256'},raw,{name:'AES-GCM',length:256},false,['encrypt','decrypt']);}})();